import React, { useState, useEffect, useMemo } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Robust Data Synchronization Logic
  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      // Force a poke to the server to wake up any dormant listeners
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      // Perform a one-time server-side fetch to ensure we're not just looking at stale cache
      await Promise.all([
        watchlistRef.get({ source: 'server' }).catch(() => watchlistRef.get()),
        historyRef.get({ source: 'server' }).catch(() => historyRef.get())
      ]);

      setIsSyncing(false);
    } catch (err: any) {
      console.warn("Sync warning (often due to offline cache):", err);
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    // Initial sync on user login
    syncData();

    const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
    const unsubWatchlist = watchlistRef.onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
        pending: doc.metadata.hasPendingWrites
      })) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);

    }, (err) => {
        console.error("Watchlist Sync Error:", err);
        setError(`DATABASE_LINK_FAILED: ${err.message}`);
    });

    const historyRef = db.collection('users').doc(user.uid).collection('history');
    const unsubHistory = historyRef.onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const hist = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as WatchHistoryItem[];
      setHistory(hist);
    }, (err) => {
        console.error("History Sync Error:", err);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      if (err.code === 'auth/popup-closed-by-user') {
        setError('Login cancelled.');
        setFormLoading(false);
        return;
      }
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;
    const existing = watchlist.find(w => w.animeId === anime.mal_id);
    if (existing) {
      alert("ENTRY ALREADY EXISTS IN DATABASE.");
      return;
    }

    try {
        const now = new Date().toISOString();
        const newEntry: Omit<WatchListEntry, 'id'> = {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          updatedAt: now
        };

        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
        await watchlistRef.add(newEntry);

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history');
            await historyRef.add({
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: now
            });
        }
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
    }
  };

  const updateEpisodes = async (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;
    const delta = newAmount - entry.watchedEpisodes;
    if (delta === 0) return;

    try {
        const now = new Date().toISOString();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        await entryRef.update({
          watchedEpisodes: newAmount,
          updatedAt: now
        });

        const historyRef = db.collection('users').doc(user.uid).collection('history');
        await historyRef.add({
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: now
        });
    } catch (err: any) {
        setError(`UPDATE_ERROR: ${err.message}`);
    }
  };

  const updateHistoryEntry = async (id: string, updates: Partial<WatchHistoryItem>) => {
    if (!user) return;
    try {
      await db.collection('users').doc(user.uid).collection('history').doc(id).update(updates);
    } catch (err: any) {
      setError(`HISTORY_SYNC_ERROR: ${err.message}`);
    }
  };

  const deleteHistoryEntry = async (id: string) => {
    if (!user) return;
    try {
      await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
    } catch (err: any) {
      setError(`HISTORY_DELETE_ERROR: ${err.message}`);
    }
  };

  const removeAnime = async (id: string) => {
    if (!user) return;
    if (window.confirm("WARNING: Confirm deletion of database entry.")) {
      try {
          const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(id);
          await entryRef.delete();
      } catch (err: any) {
          setError(`PURGE_ERROR: ${err.message}`);
      }
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-[#00ff9f]">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin" />
            <div className="font-mono text-sm animate-pulse">ESTABLISHING CONNECTION...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) {
        return (
          <>
            <HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} />
            <AmbientSound />
          </>
        );
    }

    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-[#00ff9f] flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-[#00ff9f]/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_rgba(0,255,159,0.6)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-[#00ff9f] font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-[#ff0055] bg-[#ff0055]/10 text-[#ff0055] text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className={`mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)] ${formLoading ? 'opacity-50 cursor-not-allowed' : ''}`} style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}>
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-[#00ff9f] hover:text-white font-mono hover:underline decoration-[#00ff9f] underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-[#ff0055] selection:text-white bg-black">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-black/80 backdrop-blur-md border-b border-white/10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-white group-hover:text-[#00ff9f] transition-colors">ANI<span className="text-[#00ff9f]">TRACK</span></span>

            {/* Sync Pulse Component */}
            <div className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8">
               {hasPendingWrites || isSyncing ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse" title="Syncing to Cloud...">
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCING...</span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-[#00ff9f]" title="Synchronized with Matrix">
                    <Cloud className="w-4 h-4" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">MATRIX_ONLINE</span>
                 </div>
               )}
            </div>
          </div>

          <div className="flex items-center gap-6">
            {/* Identity Badge */}
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-white leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-[#00ff9f]" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{user.email}</span>
            </div>

            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-[#ff0055] transition-all flex items-center justify-center overflow-hidden bg-black">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors" title="Sever Connection">
                  <LogOut className="w-5 h-5" />
                </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-[#ff0055]/10 border-[#ff0055] text-[#ff0055]'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div>
                  <h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3>
                  <p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p>
               </div>
            </div>
            {error && !isOffline && <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>}
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-white/10 pb-4">
             <div><h2 className="text-2xl font-black text-white uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 hover:border-[#00ff9f] text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-white uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-[#ff0055] mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-white/10 pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-white flex items-center gap-3">MEMORY BANK <span className="text-lg font-mono font-normal text-[#00ff9f] border border-[#00ff9f] px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-[#00ff9f] hover:border-[#00ff9f] transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`} title="Force Refresh from Cloud">
                   <RefreshCw className="w-4 h-4" />
                </button>
            </div>
            {watchlist.length > 0 && (
              <div className="flex items-center gap-3">
                <span className="text-[10px] font-mono text-gray-500 uppercase">Protocol:</span>
                <div className="flex gap-1">
                  <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-[#00ff9f]/20 border-[#00ff9f] text-[#00ff9f]' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                  <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-[#00ff9f]/20 border-[#00ff9f] text-[#00ff9f]' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
                </div>
              </div>
            )}
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Initializing neural link... search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard key={entry.id} entry={entry} onUpdateEpisodes={updateEpisodes} onRemove={removeAnime} />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={updateHistoryEntry} onDelete={deleteHistoryEntry} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Loader2, X, WifiOff, Hourglass, ServerCrash, AlertTriangle, CheckCircle, Sparkles, Database, BookmarkCheck } from 'lucide-react';
import { searchAnime } from '../services/jikanService';
import { getAnimeRecommendations } from '../services/geminiService';
import { Anime, WatchListEntry } from '../types';
import { CyberInput, CyberButton, CyberCard, GlitchText } from './CyberUI';

interface AnimeSearchProps {
  onAddAnime: (anime: Anime, watched: number) => void;
  watchlist: WatchListEntry[];
}

export const AnimeSearch: React.FC<AnimeSearchProps> = ({ onAddAnime, watchlist }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Anime[]>([]);
  const [loading, setLoading] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // AI State
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiRecommendations, setAiRecommendations] = useState<string>('');

  // Modal State
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);
  const [watchedInput, setWatchedInput] = useState<string>('');

  const searchContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.length > 2) {
        setLoading(true);
        setError(null);
        try {
          const data = await searchAnime(query);
          setResults(data);
          setShowResults(true);
        } catch (err: any) {
          setResults([]);
          setError(err.message || "Failed to fetch results");
          setShowResults(true);
        } finally {
          setLoading(false);
        }
      } else {
        setResults([]);
        setShowResults(false);
        setError(null);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleInitiateAdd = (anime: Anime) => {
    // Prevent adding if already in library
    if (watchlist.some(w => w.animeId === anime.mal_id)) return;

    setSelectedAnime(anime);
    setWatchedInput('0');
    setShowResults(false);
  };

  const handleConfirmAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAnime) return;

    let watched = parseInt(watchedInput, 10);
    if (isNaN(watched) || watched < 0) watched = 0;

    if (selectedAnime.episodes && watched > selectedAnime.episodes) {
      watched = selectedAnime.episodes;
    }

    onAddAnime(selectedAnime, watched);
    setSelectedAnime(null);
    setWatchedInput('');
    setQuery('');
  };

  const handleAiRecommend = async () => {
    setShowAiModal(true);
    setAiLoading(true);
    setAiRecommendations('');
    try {
      const titles = watchlist.map(w => w.title);
      const recs = await getAnimeRecommendations(titles);
      setAiRecommendations(recs);
    } catch (err) {
      setAiRecommendations("Neural link failed to generate suggestions.");
    } finally {
      setAiLoading(false);
    }
  };

  const getErrorConfig = (msg: string) => {
    if (msg.includes("Network:")) return { icon: WifiOff, text: msg.replace("Network:", "").trim(), color: "text-amber-500" };
    if (msg.includes("RateLimit:")) return { icon: Hourglass, text: "Uplink congested. Wait...", color: "text-orange-500" };
    return { icon: AlertTriangle, text: msg.replace("Error:", "").trim(), color: "text-red-500" };
  };

  return (
    <div className="relative w-full max-w-2xl mx-auto z-50" ref={searchContainerRef}>
      <div className="flex items-end gap-2">
        <div className="flex-1">
          <CyberInput
            label="Database Query"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => { if (results.length > 0 || error) setShowResults(true); }}
            placeholder="Input title sequence..."
          />
        </div>

        <button
          onClick={handleAiRecommend}
          className="h-[50px] px-4 bg-[#00baee]/10 border border-[#00baee] text-[#00baee] hover:bg-[#00baee] hover:text-black transition-all duration-300 mb-[1px]"
          title="AI Recommend"
          style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}
        >
          {aiLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
        </button>
      </div>

      {showResults && (results.length > 0 || error || loading) && (
        <div className="absolute top-full left-0 right-0 mt-2 bg-black/95 backdrop-blur-2xl border border-white/20 overflow-hidden max-h-96 overflow-y-auto z-50 animate-fade-in custom-scrollbar"
             style={{ clipPath: 'polygon(0 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%)' }}
        >
          {loading ? (
            <div className="p-10 flex flex-col items-center gap-2 text-[#00ff9f]">
              <Loader2 className="w-6 h-6 animate-spin" />
              <span className="font-mono text-[10px] uppercase tracking-widest">Querying Matrix...</span>
            </div>
          ) : error ? (
            (() => {
              const { icon: Icon, text, color } = getErrorConfig(error);
              return (
                <div className={`p-6 flex flex-col items-center justify-center ${color} gap-3 text-center border-l-2 border-red-500`}>
                  <Icon className="w-8 h-8 opacity-80" />
                  <span className="font-mono text-sm uppercase">{text}</span>
                </div>
              );
            })()
          ) : (
            results.map((anime) => {
              const isInLibrary = watchlist.some(w => w.animeId === anime.mal_id);
              return (
                <div 
                  key={anime.mal_id} 
                  className={`flex items-center p-3 cursor-pointer group border-b border-white/5 last:border-0 transition-colors ${isInLibrary ? 'opacity-60 bg-white/5 cursor-default' : 'hover:bg-[#00ff9f]/10'}`}
                  onClick={() => handleInitiateAdd(anime)}
                >
                  <div className="relative">
                    <img 
                      src={anime.images.jpg.image_url} 
                      alt={anime.title} 
                      className={`w-10 h-14 object-cover border border-white/20 transition-colors ${isInLibrary ? 'grayscale' : 'group-hover:border-[#00ff9f]'}`}
                    />
                    {isInLibrary && (
                      <div className="absolute inset-0 flex items-center justify-center bg-black/60">
                        <BookmarkCheck className="w-6 h-6 text-[#00ff9f]" />
                      </div>
                    )}
                  </div>
                  <div className="ml-4 flex-1">
                    <h4 className={`font-mono font-bold uppercase tracking-tight line-clamp-1 transition-colors ${isInLibrary ? 'text-gray-500' : 'text-gray-200 group-hover:text-[#00ff9f]'}`}>
                      {anime.title}
                    </h4>
                    <p className="text-[10px] font-mono text-gray-500">
                      <span className="text-[#00baee]">{anime.episodes ? `${anime.episodes} EPS` : 'ONGOING'}</span> // {anime.genres.slice(0, 2).map(g => g.name).join(', ')}
                    </p>
                  </div>
                  {isInLibrary ? (
                    <span className="text-[9px] font-mono text-[#00ff9f] border border-[#00ff9f]/30 px-2 py-1 uppercase tracking-tighter">In_Library</span>
                  ) : (
                    <button 
                      onClick={(e) => { e.stopPropagation(); handleInitiateAdd(anime); }}
                      className="ml-3 p-2 border border-[#00ff9f]/50 text-[#00ff9f] hover:bg-[#00ff9f] hover:text-black transition-all"
                    >
                      <Plus className="w-4 h-4" />
                    </button>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

      {/* Add Dialog Modal */}
      {selectedAnime && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
          <CyberCard className="w-full max-w-sm">
            <div className="relative h-32 bg-gray-900 border-b border-white/10 mb-4 overflow-hidden">
               <div className="absolute inset-0 bg-cover bg-center opacity-40 grayscale" style={{ backgroundImage: `url(${selectedAnime.images.jpg.large_image_url})` }} />
               <div className="absolute inset-0 bg-gradient-to-t from-black to-transparent" />
               <div className="absolute bottom-2 left-4">
                  <h3 className="text-lg font-black font-mono text-white uppercase line-clamp-1 drop-shadow-md">{selectedAnime.title}</h3>
               </div>
               <button onClick={() => setSelectedAnime(null)} className="absolute top-2 right-2 text-gray-500 hover:text-red-500 transition-colors"><X className="w-5 h-5" /></button>
            </div>

            <form onSubmit={handleConfirmAdd} className="p-4 pt-0 space-y-4">
              <p className="text-xs font-mono text-[#00ff9f] tracking-widest uppercase mb-1">&gt; Link New Record</p>
              <div>
                <label className="block text-[10px] font-mono text-gray-500 mb-2 uppercase">Initial Progress</label>
                <div className="flex items-center gap-3">
                  <input 
                    type="number" 
                    min="0"
                    max={selectedAnime.episodes || 9999}
                    value={watchedInput}
                    onChange={(e) => setWatchedInput(e.target.value)}
                    className="flex-1 bg-black border border-gray-700 text-[#00ff9f] px-4 py-2 font-mono text-xl focus:border-[#00ff9f] outline-none"
                    autoFocus
                  />
                  <div className="text-sm font-mono text-gray-600">/ {selectedAnime.episodes || '???'}</div>
                </div>
              </div>
              <div className="flex gap-3 mt-6">
                <CyberButton onClick={() => setSelectedAnime(null)} className="flex-1 text-xs">Abort</CyberButton>
                <CyberButton type="submit" primary className="flex-1 text-xs">Confirm_Sync</CyberButton>
              </div>
            </form>
          </CyberCard>
        </div>
      )}

      {/* AI Recommendations Modal */}
      {showAiModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-fade-in">
          <CyberCard className="w-full max-w-lg border-[#00baee]/50">
             <div className="bg-[#00baee]/10 p-4 border-b border-[#00baee]/30 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Database className="w-5 h-5 text-[#00baee] animate-pulse" />
                  <GlitchText className="font-mono font-bold text-[#00baee] tracking-widest">NEURAL_ANALYSIS</GlitchText>
                </div>
                <button onClick={() => setShowAiModal(false)} className="text-[#00baee] hover:text-white transition-colors"><X className="w-5 h-5" /></button>
             </div>

             <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar">
                {aiLoading ? (
                  <div className="flex flex-col items-center justify-center py-10 space-y-4">
                    <Loader2 className="w-12 h-12 text-[#00baee] animate-spin" />
                    <p className="font-mono text-xs text-[#00baee] animate-pulse">EXTRACTING DATA FROM MATRIX...</p>
                  </div>
                ) : (
                  <div className="font-mono text-sm leading-relaxed text-gray-300">
                    <div className="mb-4 text-xs text-gray-500 border-l-2 border-[#00baee] pl-3">
                      STATUS: {watchlist.length} SOURCES DETECTED.<br/>
                      ENCRYPTION: LEVEL_4
                    </div>
                    <div className="space-y-4">
                      {aiRecommendations.split('\n').map((line, i) => (
                        <p key={i} className="hover:text-white transition-colors">{line}</p>
                      ))}
                    </div>
                  </div>
                )}
             </div>
          </CyberCard>
        </div>
      )}
    </div>
  );
};
